import 'express-async-errors';            // must be first import in entry
import express, { Express } from 'express';
import helmet from 'helmet';
import cors from 'cors';
import compression from 'compression';
import pinoHttp from 'pino-http';
import rateLimit from 'express-rate-limit';
import { router } from './routes';
import { errorHandler, notFoundHandler } from './middleware/errors';
import { config } from './config';

export function createApp(): Express {
  const app = express();
  app.set('trust proxy', 1);
  app.use(helmet());
  app.use(cors({ origin: config.corsOrigins, credentials: true }));
  app.use(compression());
  app.use(express.json({ limit: '10kb' }));
  app.use(pinoHttp({
    logger: config.logger,
    redact: ['req.headers.authorization', 'req.headers.cookie',
             'req.body.password', 'req.body.token'],
    genReqId: (req) => req.headers['x-request-id'] as string ?? crypto.randomUUID(),
  }));
  app.use(rateLimit({ windowMs: 15 * 60 * 1000, max: 100, standardHeaders: true }));
  app.get('/health', (_req, res) => res.json({ status: 'ok' }));
  app.use('/api/v1', router);
  app.use(notFoundHandler);
  app.use(errorHandler);  // must be last
  return app;
}

import { createApp } from './app';
import { config, logger, db, redis } from './config';

const app = createApp();
const server = app.listen(config.port, () => logger.info({ port: config.port }, 'listening'));

async function shutdown(signal: string) {
  logger.info(`${signal} received`);
  server.close(async () => {
    logger.info('HTTP server closed');
    try {
      await db.end();
      await redis.quit();
    } catch (err) {
      logger.error({ err }, 'shutdown error');
    }
    process.exit(0);
  });
  setTimeout(() => {
    logger.error('shutdown timeout, forcing exit');
    process.exit(1);
  }, 30_000).unref();
}
process.on('SIGTERM', () => shutdown('SIGTERM'));
process.on('SIGINT',  () => shutdown('SIGINT'));

import { Type, Static } from '@sinclair/typebox';
import type { FastifyPluginAsync } from 'fastify';

const CreateUserSchema = Type.Object({
  email: Type.String({ format: 'email' }),
  name: Type.String({ minLength: 1, maxLength: 100 }),
  password: Type.String({ minLength: 8 }),
});

const UserSchema = Type.Object({
  id: Type.String({ format: 'uuid' }),
  email: Type.String(),
  name: Type.String(),
});

export const userRoutes: FastifyPluginAsync = async (app) => {
  app.post<{ Body: Static<typeof CreateUserSchema> }>(
    '/',
    {
      preHandler: [app.authenticate],
      schema: {
        body: CreateUserSchema,
        response: { 201: Type.Object({ data: UserSchema }) },
      },
    },
    async (request, reply) => {
      const user = await app.userService.createUser(request.body);
      reply.status(201);
      return { data: user };
    }
  );
};

// plugins/auth.ts — must use fastify-plugin to escape encapsulation
import fp from 'fastify-plugin';
import jwt from 'jsonwebtoken';
import type { FastifyPluginAsync, FastifyRequest } from 'fastify';

declare module 'fastify' {
  interface FastifyInstance {
    authenticate: (request: FastifyRequest) => Promise<void>;
  }
  interface FastifyRequest { user?: { userId: string; email: string }; }
}

const authPlugin: FastifyPluginAsync = async (app) => {
  app.decorate('authenticate', async (request: FastifyRequest) => {
    const header = request.headers.authorization;
    if (!header?.startsWith('Bearer '))
      throw app.httpErrors.unauthorized('Missing authorization');
    try {
      const payload = jwt.verify(header.slice(7), app.config.jwtSecret);
      request.user = payload as { userId: string; email: string };
    } catch {
      throw app.httpErrors.unauthorized('Invalid token');
    }
  });
};
export default fp(authPlugin, { name: 'auth' });

// middleware/errors.ts
import type { ErrorRequestHandler, RequestHandler } from 'express';
import { ZodError } from 'zod';

export class AppError extends Error {
  constructor(public code: string, message: string, public status = 500, public details?: unknown) {
    super(message);
  }
}
export class ValidationError  extends AppError { constructor(d?: unknown){super('VALIDATION', 'Invalid input', 400, d)} }
export class NotFoundError    extends AppError { constructor(m='Not found'){super('NOT_FOUND', m, 404)} }
export class UnauthorizedError extends AppError { constructor(m='Unauthorized'){super('UNAUTHORIZED', m, 401)} }

export const notFoundHandler: RequestHandler = (_req, _res, next) =>
  next(new NotFoundError());

export const errorHandler: ErrorRequestHandler = (err, req, res, _next) => {
  if (err instanceof ZodError)
    err = new ValidationError(err.flatten());
  if (!(err instanceof AppError))
    err = new AppError('INTERNAL', 'Internal server error', 500);
  req.log?.error({ err, reqId: req.id }, err.message);
  res.status(err.status).json({
    error: { code: err.code, message: err.message, details: err.details },
  });
};
